const items = $input.all();
const totalItems = items.length;

// Assuming TOTAL SCENES is same for all items (usually from sheet row)
const totalScenes = Number(items[0].json["TOTAL SCENES"]);

const isComplete = totalItems >= totalScenes;

for (const item of items) {
  item.json.isComplete = isComplete;
}

return items;

// n8n Code Node
const items = $input.all();

// Step 1: Group items by ID
const groups = {};
for (const item of items) {
  const id = item.json.ID;
  if (!groups[id]) groups[id] = [];
  groups[id].push(item);
}

const uniqueIds = Object.keys(groups);

// Step 2: If all items share the same ID, return all
if (uniqueIds.length === 1) {
  return items;
}

// Step 3: Find the minimum group size
const minCount = Math.min(...uniqueIds.map(id => groups[id].length));

// Step 4: Return only the group(s) with the minimum entry count
const result = [];
for (const id of uniqueIds) {
  if (groups[id].length === minCount) {
    result.push(...groups[id]);
  }
}

return result;
